1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUMS: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	  rune: 25,
9	  moonstone: 25,
10	};
11	
12	const COMPONENT_TYPES = ["rune", "moonstone"];
13	const BLOCK_SIZE = 3;
14	const BLOCK_PREMIUM = 60;
15	
16	const isComponent = (item: any): boolean =>
17	  COMPONENT_TYPES.includes(item.type);
18	
19	const itemPremiumWithModifiers = (item: any): number => {
20	  const base = BASE_PREMIUMS[item.type] ?? 0;
21	  return base
22	    + (item.cursed ? base * 0.5 : 0)
23	    + (item.enchantment >= 5 ? base * 0.3 : 0);
24	};
25	
26	const regularItemsPremium = (items: any[]): number =>
27	  items
28	    .filter((item: any) => !isComponent(item))
29	    .reduce((sum: number, item: any) => sum + itemPremiumWithModifiers(item), 0);
30	
31	const componentBlockPremium = (count: number, type: string): number =>
32	  count === BLOCK_SIZE ? BLOCK_PREMIUM : count * BASE_PREMIUMS[type];
33	
34	const countByType = (items: any[]): Record<string, number> =>
35	  items.filter(isComponent).reduce(
36	    (acc: Record<string, number>, item: any) => ({
37	      ...acc,
38	      [item.type]: (acc[item.type] ?? 0) + 1,
39	    }),
40	    {},
41	  );
42	
43	const componentsPremium = (items: any[]): number =>
44	  Object.entries(countByType(items)).reduce(
45	    (sum, [type, count]) => sum + componentBlockPremium(count, type),
46	    0,
47	  );
48	
49	const policyBasePremium = (items: any[]): number =>
50	  items
51	    .filter((item: any) => !isComponent(item))
52	    .reduce((sum: number, item: any) => sum + (BASE_PREMIUMS[item.type] ?? 0), 0)
53	  + componentsPremium(items);
54	
55	const calculateQuotePremium = (items: any[]): number => {
56	  const base = policyBasePremium(items);
57	  const itemSurcharges = regularItemsPremium(items) - items
58	    .filter((item: any) => !isComponent(item))
59	    .reduce((sum: number, item: any) => sum + (BASE_PREMIUMS[item.type] ?? 0), 0);
60	  const firstInsurance = base * 0.1;
61	  return Math.ceil(base + itemSurcharges + firstInsurance + PROCESSING_FEE);
62	};
63	
64	export function processScenario(scenario: any): any {
65	  const results = scenario.steps.map((step: any) => ({
66	    premium: calculateQuotePremium(step.items),
67	  }));
68	  return { results };
69	}
